def utc_now() -> str:
    return datetime.now(timezone.utc).isoformat()


class ElasticsearchApp:
    def __init__(self, host: str = DEFAULT_HOST, port: int = DEFAULT_PORT):
        self.logger = logging.getLogger("ElasticsearchApp")
